// subscription-vend.bicep
// Deploy at tenant scope to create a new MCA subscription
// az deployment tenant create --template-file subscription-vend.bicep --location eastus
targetScope = 'tenant'

param billingAccountName string
param billingProfileName string
param invoiceSectionName string
param subscriptionDisplayName string
param managementGroupId string

resource subscription 'Microsoft.Subscription/aliases@2021-10-01' = {
  name: subscriptionDisplayName
  properties: {
    workload: 'Production'
    displayName: subscriptionDisplayName
    billingScope: '/providers/Microsoft.Billing/billingAccounts/${billingAccountName}/billingProfiles/${billingProfileName}/invoiceSections/${invoiceSectionName}'
  }
}

// Move subscription to the target management group after creation
resource mgAssociation 'Microsoft.Management/managementGroups/subscriptions@2021-04-01' = {
  name: '${managementGroupId}/${subscription.properties.subscriptionId}'
}

output subscriptionId string = subscription.properties.subscriptionId
